// toolbar.js
import { NODES } from './nodes/nodeRegistry';

const DraggableNode = ({ type, label }) => {
  const onDragStart = (e) => {
    e.dataTransfer.setData('application/reactflow', JSON.stringify({ nodeType: type }));
    e.dataTransfer.effectAllowed = 'move';
  };

  return (
    <div className="pf-draggable-node" draggable onDragStart={onDragStart}>
      {label}
    </div>
  );
};

// Group nodes by category
const CATEGORIES = {
  io:      { label: 'I/O',     nodes: [] },
  ai:      { label: 'AI',      nodes: [] },
  data:    { label: 'Data',    nodes: [] },
  logic:   { label: 'Logic',   nodes: [] },
  utility: { label: 'Utility', nodes: [] },
};

NODES.forEach(n => {
  if (CATEGORIES[n.category]) CATEGORIES[n.category].nodes.push(n);
});

export const PipelineToolbar = () => (
  <div className="pf-toolbar">
    <div className="pf-toolbar-brand">
      Pipe<span>Forge</span>
    </div>
    <div className="pf-toolbar-divider" />
    {Object.entries(CATEGORIES).map(([key, cat]) =>
      cat.nodes.length > 0 && (
        <div key={key} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <span className="pf-toolbar-label">{cat.label}</span>
          <div className="pf-toolbar-nodes">
            {cat.nodes.map(n => (
              <DraggableNode key={n.type} type={n.type} label={n.label} />
            ))}
          </div>
          <div className="pf-toolbar-divider" />
        </div>
      )
    )}
  </div>
);
